import{_ as n,y as o,a,o as i,a2 as r,D as s}from"./chunks/framework.DCcmcJcL.js";const A=JSON.parse('{"title":"Return Merchandise Authorization (RMA)","description":"","frontmatter":{},"headers":[],"relativePath":"orders/rma.md","filePath":"orders/rma.md","lastUpdated":1781165799000}'),g={name:"orders/rma.md"};function l(u,e,p,d,m,h){const t=o("ImagePopup");return i(),a("div",null,[e[0]||(e[0]=r('<h1 id="return-merchandise-authorization-rma" tabindex="-1">Return Merchandise Authorization (RMA) <a class="header-anchor" href="#return-merchandise-authorization-rma" aria-label="Permalink to &quot;Return Merchandise Authorization (RMA)&quot;">​</a></h1><p>The Return Merchandise Authorization (RMA) feature in Bagisto allows customers or guests to request returns, replacements, or cancellations for their orders within a defined time period. This structured process ensures efficient handling of after-sales support and improves customer satisfaction.</p><h2 id="admin-configuration" tabindex="-1">Admin Configuration <a class="header-anchor" href="#admin-configuration" aria-label="Permalink to &quot;Admin Configuration&quot;">​</a></h2><p>Before using the RMA feature, it must be configured from the Admin panel.</p><h3 id="configure-rma" tabindex="-1">Configure RMA <a class="header-anchor" href="#configure-rma" aria-label="Permalink to &quot;Configure RMA&quot;">​</a></h3><p><strong>Step 1:</strong> Navigate to <strong>Configure &gt; Sales &gt; RMA</strong> in the Admin panel.</p><p><strong>Step 2:</strong> Configure other settings such as:</p><ul><li><strong>Default Allowed Days</strong></li><li><strong>Return Policy</strong></li><li><strong>Allowed File Extension</strong></li><li><strong>Allow New RMA for Cancelled Request</strong></li><li><strong>Allow New RMA for Declined Request</strong></li><li><strong>Allow Product Types for RMA</strong></li></ul>',8)),s(t,{src:"/images/orders/rma-config.png",alt:"RMA configuration"}),e[1]||(e[1]=r('<h3 id="rma-reasons" tabindex="-1">RMA Reasons <a class="header-anchor" href="#rma-reasons" aria-label="Permalink to &quot;RMA Reasons&quot;">​</a></h3><p>The Admin can define predefined reasons that customers can select when submitting an RMA request.</p><p><strong>Step 1:</strong> Go to <strong>Sales &gt; RMA &gt; Reasons</strong>.</p><p><strong>Step 2:</strong> Click <strong>Create Reason</strong>.</p><p><strong>Step 3:</strong> Enter the reason title and select the <strong>Resolution Type</strong> (Return, Cancel).</p><p><strong>Step 4:</strong> Click <strong>Save Reason</strong>.</p>',6)),s(t,{src:"/images/orders/rma-reason.png",alt:"RMA reason"}),e[2]||(e[2]=r('<h3 id="rma-rules" tabindex="-1">RMA Rules <a class="header-anchor" href="#rma-rules" aria-label="Permalink to &quot;RMA Rules&quot;">​</a></h3><p>Rules define the policies for returns and exchanges, such as the maximum number of days allowed for a request.</p><p><strong>Step 1:</strong> Go to <strong>Sales &gt; RMA &gt; Rules</strong>.</p><p><strong>Step 2:</strong> Click <strong>Create Rule</strong>.</p><p><strong>Step 3:</strong> Set the <strong>Resolutions Period</strong> for Exchange and Return.</p><p><strong>Step 4:</strong> Define the rule&#39;s title, status, and description.</p><p><strong>Step 5:</strong> Click <strong>Save Rule</strong>.</p>',7)),s(t,{src:"/images/orders/rma-rules.png",alt:"RMA rules"}),e[3]||(e[3]=r('<h3 id="rma-statuses" tabindex="-1">RMA Statuses <a class="header-anchor" href="#rma-statuses" aria-label="Permalink to &quot;RMA Statuses&quot;">​</a></h3><p>Statuses represent the different stages of an RMA request (e.g., Pending, Approved, Solved).</p><p><strong>Step 1:</strong> Go to <strong>Sales &gt; RMA &gt; Statuses</strong>.</p><p><strong>Step 2:</strong> Click <strong>Create Status</strong>.</p><p><strong>Step 3:</strong> Enter the status title and choose a color for easy identification.</p><p><strong>Step 4:</strong> Click <strong>Save Status</strong>.</p>',6)),s(t,{src:"/images/orders/rma-status.png",alt:"RMA status"}),e[4]||(e[4]=r('<h2 id="rma-management-admin" tabindex="-1">RMA Management (Admin) <a class="header-anchor" href="#rma-management-admin" aria-label="Permalink to &quot;RMA Management (Admin)&quot;">​</a></h2><p>Admins can manage all RMA requests from a central dashboard.</p><h3 id="handling-requests" tabindex="-1">Handling Requests <a class="header-anchor" href="#handling-requests" aria-label="Permalink to &quot;Handling Requests&quot;">​</a></h3><p><strong>Step 1:</strong> Navigate to <strong>Sales &gt; RMA &gt; Requests</strong>.</p><p><strong>Step 2:</strong> Click on an RMA request to view its details.</p><p><strong>Step 3:</strong> The Admin can:</p><ul><li>Update the <strong>RMA Status</strong>.</li><li>Communcate with the customer via messages.</li><li>Add internal notes or attachments.</li><li>View the items requested for return/exchange.</li></ul><h2 id="how-customers-create-an-rma-request" tabindex="-1">How Customers Create an RMA Request <a class="header-anchor" href="#how-customers-create-an-rma-request" aria-label="Permalink to &quot;How Customers Create an RMA Request&quot;">​</a></h2><p>Customers can initiate an RMA request from their account profile.</p><p><strong>Step 1:</strong> Log in to the customer account and go to <strong>Profile &gt; RMA</strong>.</p><p><strong>Step 2:</strong> Click <strong>Create Return Request</strong>.</p><p><strong>Step 3:</strong> Select the <strong>Order ID</strong> for which the return is requested.</p><p><strong>Step 4:</strong> Select the items, specify the quantity, and choose a <strong>Reason</strong> and <strong>Resolution Type</strong>.</p><p><strong>Step 5:</strong> Add any additional information or images if required.</p><p><strong>Step 6:</strong> Click <strong>Submit</strong>.</p>',15)),s(t,{src:"/images/orders/rma-request-customer.png",alt:"RMA request customer"})])}const R=n(g,[["render",l]]);export{A as __pageData,R as default};
